delegate.full_source:
import { Effect, Schema } from "effect"
import * as Tool from "./tool"
import { Coordination } from "./coordination"

const Parameters = Schema.Struct({
  subagent_type: Schema.String.annotate({
    description: "Target subagent type for delegation",
  }),
  prompt: Schema.String.annotate({
    description: "Delegation prompt for the subagent",
  }),
  description: Schema.optional(Schema.String).annotate({
    description: "Human-readable description of the delegation",
  }),
  wave: Schema.optional(Schema.Number).annotate({
    description: "Coordination wave number for fan-out grouping",
  }),
  wave_type: Schema.optional(Schema.String).annotate({
    description: "Wave type for fan-out grouping (learning, execution, validation, etc.)",
  }),
})

export const DelegateTool = Tool.define(
  "delegate",
  Effect.succeed({
    description:
      "Record a subagent delegation in the coordination ledger. Generates a unique task ID and claims the task to ensure cross-session visibility and conflict detection.",
    parameters: Parameters,
    execute: (params: Schema.Schema.Type<typeof Parameters>, ctx: Tool.Context) =>
      Effect.gen(function* () {
        const taskId = `del_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

        yield* Coordination.claimTask(
          taskId,
          ctx.sessionID,
          params.subagent_type,
          params.description ?? "",
          params.wave ?? 0,
          (params.wave_type ?? "") as Coordination.WaveType | "",
        )

        const result = {
          task_id: taskId,
          subagent_type: params.subagent_type,
          session_id: ctx.sessionID,
          status: "claimed" as const,
        }

        return {
          title: "delegate",
          metadata: {
            task_id: taskId,
            subagent_type: params.subagent_type,
            status: "claimed",
          },
          output: JSON.stringify(result, null, 2),
        }
      }).pipe(Effect.orDie),
  }),
)

export * as Delegate from "./delegate"

session_diff.full_source:
import { Effect, Schema } from "effect"
import * as Tool from "./tool"
import { AppFileSystem } from "@opencode-ai/core/filesystem"
import { InstanceState } from "@/effect/instance-state"
import path from "path"

const Parameters = Schema.Struct({
  session_id: Schema.optional(Schema.String).annotate({
    description: "Session ID to diff. Defaults to the current session.",
  }),
  format: Schema.optional(Schema.String).annotate({
    description: "Output format: 'summary' (counts per file, default) or 'full' (all record details)",
  }),
})

export const SessionDiffTool = Tool.define(
  "session_diff",
  Effect.gen(function* () {
    const fs = yield* AppFileSystem.Service

    return {
      description:
        "Generate a consolidated diff summary of all changes made in this session. Reads the edit_log.v1.jsonl and groups edits by file path, counting operations per file.",
      parameters: Parameters,
      execute: (params: Schema.Schema.Type<typeof Parameters>, ctx: Tool.Context) =>
        Effect.gen(function* () {
          const instance = yield* InstanceState.context
          const sessionId = params.session_id ?? ctx.sessionID
          const editLogPath = path.join(
            instance.directory,
            "docs",
            "json",
            "opencode",
            "sessions",
            sessionId,
            "edits",
            "edit_log.v1.jsonl",
          )
          const format = params.format ?? "summary"

          if (!(yield* fs.existsSafe(editLogPath))) {
            const result = {
              status: "empty" as const,
              session_id: sessionId,
              note: "No edit log found",
            }
            return {
              title: "session_diff",
              metadata: { session_id: sessionId, status: "empty" },
              output: JSON.stringify(result, null, 2),
            }
          }

          const content = yield* fs.readFileString(editLogPath)
          const lines = content.trim().split("\n").filter(Boolean)

          const records: Array<Record<string, unknown>> = []
          for (const line of lines) {
            try {
              records.push(JSON.parse(line))
            } catch {
              // skip malformed lines
            }
          }

          // Group by file path
          const files: Record<string, { edits: number; lines_changed: number; records: Array<Record<string, unknown>> }> = {}
          for (const record of records) {
            const file = String(record.file ?? "unknown")
            if (!files[file]) {
              files[file] = { edits: 0, lines_changed: 0, records: [] }
            }
            files[file].edits++
            const changeSummary = String(record.change_summary ?? "")
            const linesMatch = changeSummary.match(/^(\d+) lines? changed$/)
            if (linesMatch) {
              files[file].lines_changed += Number(linesMatch[1])
            }
            files[file].records.push(record)
          }

          if (format === "full") {
            const result = {
              status: "ok" as const,
              session_id: sessionId,
              format: "full" as const,
              files: Object.fromEntries(
                Object.entries(files).map(([file, info]) => [
                  file,
                  {
                    edits: info.edits,
                    lines_changed: info.lines_changed,
                    records: info.records,
                  },
                ]),
              ),
              total_edits: records.length,
              total_files: Object.keys(files).length,
            }
            return {
              title: "session_diff",
              metadata: { session_id: sessionId, status: "ok", format: "full" },
              output: JSON.stringify(result, null, 2),
            }
          }

          // Summary: only counts per file
          const summary: Record<string, { edits: number; lines_changed: number }> = {}
          for (const [file, info] of Object.entries(files)) {
            summary[file] = {
              edits: info.edits,
              lines_changed: info.lines_changed,
            }
          }

          const result = {
            status: "ok" as const,
            session_id: sessionId,
            format: "summary" as const,
            files: summary,
            total_edits: records.length,
            total_files: Object.keys(files).length,
          }

          return {
            title: "session_diff",
            metadata: { session_id: sessionId, status: "ok", format: "summary" },
            output: JSON.stringify(result, null, 2),
          }
        }).pipe(Effect.orDie),
    }
  }),
)

export * as SessionDiff from "./session-diff"
